void app_main(void)
{
    // Initialize NVS flash storage for WiFi configuration
    esp_err_t ret = nvs_flash_init();
    if (ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        // If NVS corruption detected, erase and reinitialize
        ESP_ERROR_CHECK(nvs_flash_erase());
        ret = nvs_flash_init();
    }
    ESP_ERROR_CHECK(ret);

    // Initialize WiFi configuration
    wifi_init_config_t cfg = WIFI_INIT_CONFIG_DEFAULT();
    ESP_ERROR_CHECK(esp_wifi_init(&cfg));

    // Set WiFi mode to station
    ESP_ERROR_CHECK(esp_wifi_set_mode(WIFI_MODE_STA));

    // Start WiFi
    ESP_ERROR_CHECK(esp_wifi_start());

    // Initialize application components
    audio_processing_init();
    network_communication_init();
    device_state_manager_init();

    // Main application event loop
    while (1) {
        // Handle audio processing tasks
        audio_processing_task();

        // Handle network communication tasks
        network_communication_task();

        // Handle device state management tasks
        device_state_manager_task();

        // Small delay to prevent blocking
        vTaskDelay(10 / portTICK_PERIOD_MS);
    }
}

