std::unique_ptr<HttpClient> Ota::SetupHttp()
{
    // Create HTTP client instance
    auto httpClient = std::make_unique<HttpClient>();

    // Set device identification header
    httpClient->setHeader("Device-ID", GetDeviceId());

    // Set user agent header
    httpClient->setHeader("User-Agent", "OTA-Client/1.0");

    // Set language header
    httpClient->setHeader("Accept-Language", "en-US,en;q=0.9");

    // Set content type header
    httpClient->setHeader("Content-Type", "application/octet-stream");

    // Set conditional serial number based on device provisioning status
    if (IsDeviceProvisioned())
    {
        httpClient->setHeader("Serial-Number", GetDeviceSerialNumber());
    }

    // Set additional security headers if needed
    httpClient->setHeader("Connection", "keep-alive");

    // Configure timeout settings for OTA operations
    httpClient->setTimeout(30000); // 30 seconds timeout

    return httpClient;
}

int Ota::CheckVersion()
{
    // Initialize variables
    int result = 0;
    bool updateAvailable = false;
    std::string response;
    Json::Value root;

    // Send HTTP request to firmware update server
    result = SendHttpRequest("GET", "/firmware/version", response);
    if (result != 0)
    {
        return OTA_ERROR_HTTP_REQUEST_FAILED;
    }

    // Parse JSON response
    Json::CharReaderBuilder readerBuilder;
    Json::String errs;

    if (!Json::parseFromStream(readerBuilder, response, &root, &errs))
    {
        return OTA_ERROR_JSON_PARSE_FAILED;
    }

    // Extract version information from JSON response
    std::string latestVersion = root["version"].asString();
    std::string downloadUrl = root["download_url"].asString();
    std::string releaseNotes = root["release_notes"].asString();

    // Compare current version with latest version
    if (CompareVersions(currentFirmwareVersion, latestVersion) < 0)
    {
        updateAvailable = true;
    }

    // If update is available, proceed with update process
    if (updateAvailable)
    {
        // Store update information
        pendingUpdate.version = latestVersion;
        pendingUpdate.downloadUrl = downloadUrl;
        pendingUpdate.releaseNotes = releaseNotes;

        // Check for activation data in response
        if (root.isMember("activation_data"))
        {
            Json::Value activationData = root["activation_data"];

            // Process activation related data
            std::string activationKey = activationData["key"].asString();
            std::string activationValue = activationData["value"].asString();

            // Store activation data for later use
            activationDataMap[activationKey] = activationValue;
        }

        // Check for MQTT configuration updates
        if (root.isMember("mqtt_config"))
        {
            Json::Value mqttConfig = root["mqtt_config"];

            // Update MQTT configuration parameters
            mqttBrokerAddress = mqttConfig["broker_address"].asString();
            mqttBrokerPort = mqttConfig["broker_port"].asInt();
            mqttClientId = mqttConfig["client_id"].asString();

            // Update MQTT credentials if present
            if (mqttConfig.isMember("username"))
            {
                mqttUsername = mqttConfig["username"].asString();
            }

            if (mqttConfig.isMember("password"))
            {
                mqttPassword = mqttConfig["password"].asString();
            }

            // Notify MQTT subsystem about configuration changes
            NotifyMqttConfigChanged();
        }

        // Log the update availability
        LogInfo("New firmware version %s is available for download", latestVersion.c_str());

        // Set update flag
        firmwareUpdatePending = true;
    }
    else
    {
        // No update available
        LogInfo("Current firmware version %s is up to date", currentFirmwareVersion.c_str());
    }

    // Return success
    return OTA_SUCCESS;
}

bool Ota::MarkCurrentVersionValid()
{
    // Log the start of the validation process
    LOG_DEBUG("Starting MarkCurrentVersionValid process");

    // Get the currently running partition
    Partition* currentPartition = GetCurrentRunningPartition();
    if (currentPartition == nullptr)
    {
        LOG_ERROR("Failed to get current running partition");
        return false;
    }

    // Check if this is the factory partition - skip validation for factory
    if (currentPartition->IsFactoryPartition())
    {
        LOG_INFO("Skipping validation for factory partition");
        return true; // Success - no action needed
    }

    // Check if the current partition is in pending verification state
    if (!currentPartition->IsPendingVerification())
    {
        LOG_INFO("Current partition is not in pending verification state");
        return true; // Success - no action needed
    }

    // Mark the partition as valid
    bool result = currentPartition->MarkAsValid();
    if (!result)
    {
        LOG_ERROR("Failed to mark current partition as valid");
        return false;
    }

    // Log successful completion
    LOG_DEBUG("Successfully marked current partition as valid");

    // Optional: Update any additional OTA metadata or state tracking
    UpdateOtaState(OtaState::VALIDATED);

    return true;
}

