                    // Calculate speed (bytes per second)
                    auto currentTime = std::chrono::high_resolution_clock::now();
                    auto duration = std::chrono::duration_cast<std::chrono::seconds>(currentTime - startTime).count();
                    size_t speed = (duration > 0) ? (downloadedBytes / duration) : downloadedBytes;

                    // Report progress and speed
                    if (progressCallback) {
                        progressCallback(progress, speed);
                    }

                    // Print progress for debugging
                    if (progress % 10 == 0) {
                        std::cout << "Download progress: " << progress << "% (" 
                                  << downloadedBytes << "/" << totalSize << " bytes)" << std::endl;
                    }
                }

                // Step 3: Verify firmware header integrity
                std::cout << "Verifying firmware header integrity..." << std::endl;
                std::this_thread::sleep_for(std::chrono::milliseconds(300));

                // Simulate header verification (in real implementation, this would check CRC/checksum)
                bool headerValid = true;
                if (!headerValid) {
                    throw std::runtime_error("Firmware header verification failed");
                }

                // Step 4: Check version compatibility
                std::cout << "Checking version compatibility..." << std::endl;
                std::this_thread::sleep_for(std::chrono::milliseconds(200));

                // Simulate version checking (in real implementation, this would compare versions)
                bool versionCompatible = true;
                if (!versionCompatible) {
                    throw std::runtime_error("New firmware version is not compatible with current system");
                }

                // Step 5: Write firmware to OTA partition (simulated)
                std::cout << "Writing firmware to OTA partition..." << std::endl;
                const size_t writeSize = totalSize;
                size_t writtenBytes = 0;

                while (writtenBytes < writeSize) {
                    std::this_thread::sleep_for(std::chrono::milliseconds(5));
                    writtenBytes += chunkSize;
                    if (writtenBytes > writeSize) {
                        writtenBytes = writeSize;
                    }

                    int writeProgress = (int)((writtenBytes * 100) / writeSize);
                    if (writeProgress % 10 == 0) {
                        std::cout << "Write progress: " << writeProgress << "%" << std::endl;
                    }
                }

                // Step 6: Final verification
                std::cout << "Performing final firmware verification..." << std::endl;
                std::this_thread::sleep_for(std::chrono::milliseconds(500));

                // Simulate final verification
                bool finalVerification = true;
                if (!finalVerification) {
                    throw std::runtime_error("Final firmware verification failed");
                }

                std::cout << "Firmware upgrade completed successfully!" << std::endl;
                std::cout << "Please reboot the device to apply the new firmware." << std::endl;

            } catch (const std::exception& e) {
                std::cerr << "Firmware upgrade failed: " << e.what() << std::endl;
                throw; // Re-throw the exception for error handling upstream
            }
        }
    };
}

std::vector<int> Ota::ParseVersion(const std::string& versionString) {
    std::vector<int> result;

    // Handle empty string
    if (versionString.empty()) {
        return result;
    }

    // Split the string by '.'
    size_t start = 0;
    size_t end = 0;

    while (end != std::string::npos) {
        end = versionString.find('.', start);
        std::string component = versionString.substr(start, end - start);

        // Convert component to integer and add to result
        if (!component.empty()) {
            try {
                int versionComponent = std::stoi(component);
                result.push_back(versionComponent);
            } catch (const std::exception&) {
                // If conversion fails, skip this component
                // or handle as needed based on requirements
                continue;
            }
        }

        start = end + 1;
    }

    return result;
}

bool Ota::IsNewVersionAvailable(const std::string& currentVersion, const std::string& candidateVersion) {
    // Helper function to parse version string into segments
    auto parseVersion = [](const std::string& versionStr) -> std::vector<int> {
        std::vector<int> segments;
        std::string segment;

        for (size_t i = 0; i <= versionStr.length(); ++i) {
            if (i < versionStr.length() && versionStr[i] != '.') {
                segment += versionStr[i];
            } else {
                if (!segment.empty()) {
                    try {
                        segments.push_back(std::stoi(segment));
                    } catch (const std::exception&) {
                        // Handle invalid numeric segments by treating them as 0
                        segments.push_back(0);
                    }
                    segment.clear();
                }
            }
        }
        return segments;
    };

    // Parse both version strings
    std::vector<int> currentSegments = parseVersion(currentVersion);
    std::vector<int> candidateSegments = parseVersion(candidateVersion);

    // Compare segment by segment
    size_t maxSegments = std::max(currentSegments.size(), candidateSegments.size());

    for (size_t i = 0; i < maxSegments; ++i) {
        int currentSegment = (i < currentSegments.size()) ? currentSegments[i] : 0;
        int candidateSegment = (i < candidateSegments.size()) ? candidateSegments[i] : 0;

        if (candidateSegment > currentSegment) {
            return true;  // Candidate version is newer
        } else if (candidateSegment < currentSegment) {
            return false; // Current version is newer
        }
        // If segments are equal, continue to next segment
    }

    // All segments are equal, no new version available
    return false;
}

std::string Ota::GetActivationPayload() {
    // Check if device serial number is available
    std::string serialNumber = GetDeviceSerialNumber();
    if (serialNumber.empty()) {
        return "{}";
    }

    // Generate challenge string (this could be random or derived from system)
    std::string challenge = GenerateChallengeString();

    // Create the payload structure
    Json::Value payload;
    payload["serialNumber"] = serialNumber;
    payload["challenge"] = challenge;

    // Convert payload to string for signing
    Json::StreamWriterBuilder builder;
    builder["indentation"] = "";
    std::string payloadStr = Json::writeString(builder, payload);

    // Generate HMAC-SHA256 signature using hardware-backed key
    std::string signature = GenerateHmacSignature(payloadStr);

    // Add signature to payload
    payload["signature"] = signature;

    // Return final JSON string
    return Json::writeString(builder, payload);
}

int Ota::Activate()
{
    // Initialize variables
    int httpStatus = 0;
    int result = 0;

    // Construct activation URL - typically includes device ID and update information
    std::string activationUrl = "https://ota-server.com/activate";

    // Prepare payload data (JSON format)
    std::string payload = "{";
    payload += "\"deviceId\":\"" + GetDeviceId() + "\",";
    payload += "\"firmwareVersion\":\"" + GetCurrentFirmwareVersion() + "\",";
    payload += "\"activationTime\":" + std::to_string(GetCurrentTimestamp());
    payload += "}";

    // Set up HTTP headers
    std::map<std::string, std::string> headers;
    headers["Content-Type"] = "application/json";
    headers["Content-Length"] = std::to_string(payload.length());

    // Send HTTP POST request
    try {
        // In embedded systems, this would typically use a HTTP client library
        // For example: HttpClient::Post(activationUrl, payload, headers, &httpStatus);

        // Simulate HTTP communication (actual implementation would use network stack)
        result = SendHttpRequest(activationUrl, payload, headers, &httpStatus);

        if (result != 0) {
            return OTA_ERROR_NETWORK_FAILED;
        }

        // Handle different HTTP status codes
        switch (httpStatus) {
            case 200: // Success
                return OTA_SUCCESS;
            case 400: // Bad Request
                return OTA_ERROR_INVALID_REQUEST;
            case 401: // Unauthorized
                return OTA_ERROR_UNAUTHORIZED;
            case 404: // Not Found
                return OTA_ERROR_NOT_FOUND;
            case 500: // Internal Server Error
                return OTA_ERROR_SERVER_ERROR;
            case 503: // Service Unavailable
                return OTA_ERROR_SERVICE_UNAVAILABLE;
            default:
                // Handle other error cases
                if (httpStatus >= 400) {
                    return OTA_ERROR_HTTP_FAILURE;
                } else {
                    return OTA_ERROR_UNKNOWN;
                }
        }
    }
    catch (const std::exception& e) {
        // Handle exceptions that might occur during network operations
        return OTA_ERROR_EXCEPTION;
    }

    return OTA_ERROR_UNKNOWN;
}

