bool SetString(const std::string& key, const std::string& value) {
    // Check if namespace is available and writable
    if (!isNamespaceWritable()) {
        ESP_LOG_WARN(TAG, "Namespace is read-only, cannot set string: %s", key.c_str());
        return false;
    }

    // Attempt to store the key-value pair in NVS
    esp_err_t err = nvs_set_str(nvs_handle, key.c_str(), value.c_str());

    if (err != ESP_OK) {
        ESP_LOG_ERROR(TAG, "Failed to set string in NVS: %s, error: %s", 
                     key.c_str(), esp_err_to_name(err));
        return false;
    }

    // Mark settings as dirty to indicate unsaved changes
    settings_dirty = true;

    // Commit the changes to NVS
    err = nvs_commit(nvs_handle);
    if (err != ESP_OK) {
        ESP_LOG_ERROR(TAG, "Failed to commit NVS changes for key: %s, error: %s", 
                     key.c_str(), esp_err_to_name(err));
        return false;
    }

    ESP_LOG_DEBUG(TAG, "Successfully set string in NVS: %s = %s", 
                 key.c_str(), value.c_str());

    return true;
}

