bool Settings::GetBool(const std::string& key, bool default_value) {
    bool value = default_value;

    // Attempt to read the boolean value from NVS
    esp_err_t err = nvs_get_bool(nvs_handle_, key.c_str(), &value);

    // Check if the operation was successful
    if (err == ESP_OK) {
        return value;
    }

    // Handle error cases - return default value when key not found or read fails
    if (err == ESP_ERR_NVS_NOT_FOUND) {
        // Key doesn't exist in NVS, return default
        return default_value;
    }

    // Other errors (corruption, etc.), return default value
    return default_value;
}

void SetBool(const std::string& key, bool value) {
    // Check if the namespace is open for writing
    if (!isNamespaceWritable()) {
        // Log warning message if namespace is not writable
        logWarning("Namespace is not writable, cannot set boolean value for key: " + key);
        return;
    }

    // Convert boolean value to uint8_t (1 for true, 0 for false)
    uint8_t boolValue = value ? 1 : 0;

    // Store the boolean value in NVS
    esp_err_t result = nvs_set_u8(handle, key.c_str(), boolValue);

    // Check if the operation was successful
    if (result != ESP_OK) {
        logError("Failed to store boolean value in NVS for key: " + key);
        return;
    }

    // Mark the settings as dirty (indicates changes need to be committed)
    markSettingsDirty();

    // Commit the changes to NVS
    result = nvs_commit(handle);
    if (result != ESP_OK) {
        logError("Failed to commit boolean value to NVS for key: " + key);
    }
}

bool EraseKey(const std::string& key) {
    // Check if the NVS namespace is open for writing
    if (!IsNamespaceWritable()) {
        // Log warning if namespace is read-only
        ESP_LOGW("NVS", "Cannot erase key '%s': Namespace is read-only", key.c_str());
        return false;
    }

    // Attempt to erase the key from NVS
    esp_err_t result = nvs_erase_key(nvs_handle_, key.c_str());

    // Handle different error cases
    if (result == ESP_ERR_NVS_NOT_FOUND) {
        // Key doesn't exist - handle gracefully without throwing exception
        ESP_LOGD("NVS", "Key '%s' not found in NVS, nothing to erase", key.c_str());
        return true; // Return true as there's nothing to do
    } else if (result != ESP_OK) {
        // Other NVS errors
        ESP_LOGE("NVS", "Failed to erase key '%s': %s", key.c_str(), esp_err_to_name(result));
        return false;
    }

    // Commit the changes to NVS
    result = nvs_commit(nvs_handle_);
    if (result != ESP_OK) {
        ESP_LOGE("NVS", "Failed to commit erase of key '%s': %s", key.c_str(), esp_err_to_name(result));
        return false;
    }

    ESP_LOGI("NVS", "Successfully erased key '%s'", key.c_str());
    return true;
}

esp_err_t Settings::EraseAll()
{
    // Check if NVS namespace is open for writing
    if (!isWritable())
    {
        // Log warning message for read-only namespace
        ESP_LOGW("Settings", "Cannot erase all settings: NVS namespace is read-only");
        return ESP_ERR_NVS_READ_ONLY;
    }

    // Attempt to erase all settings in the NVS namespace
    esp_err_t err = nvs_erase_all(handle_);
    if (err != ESP_OK)
    {
        ESP_LOGE("Settings", "Failed to erase all settings: %s", esp_err_to_name(err));
        return err;
    }

    // Commit the changes to flash
    err = nvs_commit(handle_);
    if (err != ESP_OK)
    {
        ESP_LOGE("Settings", "Failed to commit erased settings: %s", esp_err_to_name(err));
        return err;
    }

    ESP_LOGI("Settings", "Successfully erased all settings from NVS");
    return ESP_OK;
}

