    // Validate input parameters
    if (buffer == nullptr || samples <= 0) {
        return 0;
    }

    // Use ESP-IDF codec device API to read audio data
    // The function expects 16-bit PCM samples
    int actual_samples = 0;

    // Perform the read operation using the codec device API
    esp_err_t result = codec_dev_->read(codec_dev_, buffer, samples * sizeof(int16_t), &actual_samples);

    // Handle potential errors
    if (result != ESP_OK) {
        // Log error or handle appropriately based on system requirements
        return 0;
    }

    // Return the number of samples actually read
    // Note: actual_samples is in bytes, so we need to convert to sample count
    // Assuming each sample is 2 bytes (16-bit)
    return actual_samples / sizeof(int16_t);
