AudioDebugger::AudioDebugger(const std::string& serverIp, int serverPort)
{
    // Initialize logging
    Logger::log("AudioDebugger: Initializing UDP socket connection");

    // Store server configuration
    m_serverIp = serverIp;
    m_serverPort = serverPort;

    // Initialize socket
    m_socketFd = socket(AF_INET, SOCK_DGRAM, 0);
    if (m_socketFd < 0) {
        Logger::log("AudioDebugger: Failed to create UDP socket", LogLevel::ERROR);
        m_initialized = false;
        return;
    }

    // Set up server address structure
    memset(&m_serverAddr, 0, sizeof(m_serverAddr));
    m_serverAddr.sin_family = AF_INET;
    m_serverAddr.sin_port = htons(serverPort);

    // Parse IP address
    if (inet_pton(AF_INET, serverIp.c_str(), &m_serverAddr.sin_addr) <= 0) {
        Logger::log("AudioDebugger: Failed to parse server IP address", LogLevel::ERROR);
        close(m_socketFd);
        m_initialized = false;
        return;
    }

    // Set socket options for better performance
    int opt = 1;
    if (setsockopt(m_socketFd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt)) < 0) {
        Logger::log("AudioDebugger: Failed to set socket options", LogLevel::WARNING);
    }

    // Log successful initialization
    Logger::log("AudioDebugger: UDP socket initialized successfully");
    Logger::log("AudioDebugger: Connected to " + serverIp + ":" + std::to_string(serverPort));

    m_initialized = true;
}

