void AudioDebugger::Feed(const std::vector<int16_t>& audioSamples)
{
#if defined(AUDIO_DEBUG_ENABLED)
    // Check if we have valid data to send
    if (audioSamples.empty()) {
        return;
    }

    try {
        // Create UDP socket
        int sock = socket(AF_INET, SOCK_DGRAM, 0);
        if (sock < 0) {
            // Log error - failed to create socket
            return;
        }

        // Set up server address structure
        struct sockaddr_in serverAddr;
        memset(&serverAddr, 0, sizeof(serverAddr));
        serverAddr.sin_family = AF_INET;
        serverAddr.sin_port = htons(m_serverPort);  // Assuming m_serverPort is member variable
        inet_pton(AF_INET, m_serverAddress.c_str(), &serverAddr.sin_addr);  // Assuming m_serverAddress is member variable

        // Convert vector of int16_t to bytes for transmission
        size_t dataSize = audioSamples.size() * sizeof(int16_t);
        const char* dataPtr = reinterpret_cast<const char*>(audioSamples.data());

        // Send data over UDP
        ssize_t sentBytes = sendto(sock, dataPtr, dataSize, 0, 
                                  reinterpret_cast<struct sockaddr*>(&serverAddr), 
                                  sizeof(serverAddr));

        // Log result
        if (sentBytes == static_cast<ssize_t>(dataSize)) {
            // Success - log successful transmission
            // Assuming there's a logging mechanism available
            LogDebug("AudioDebugger: Successfully sent %zu bytes to %s:%d", 
                    dataSize, m_serverAddress.c_str(), m_serverPort);
        } else {
            // Failed to send complete data
            LogError("AudioDebugger: Failed to send complete audio data. Sent %zd of %zu bytes", 
                    sentBytes, dataSize);
        }

        // Close socket
        close(sock);
    }
    catch (const std::exception& e) {
        // Log exception
        LogError("AudioDebugger: Exception during audio feed: %s", e.what());
    }
#endif
}

