bool CustomWakeWord::ParseWakenetModelConfig(const std::string& configFilePath) {
    // Open and read the JSON configuration file
    std::ifstream configFile(configFilePath);
    if (!configFile.is_open()) {
        LOG_ERROR("Failed to open configuration file: %s", configFilePath.c_str());
        return false;
    }

    // Read the entire file content into a string
    std::stringstream buffer;
    buffer << configFile.rdbuf();
    std::string jsonContent = buffer.str();
    configFile.close();

    // Parse the JSON content
    try {
        nlohmann::json configJson = nlohmann::json::parse(jsonContent);

        // Extract language setting
        if (configJson.contains("language")) {
            m_language = configJson["language"].get<std::string>();
            LOG_DEBUG("Parsed language: %s", m_language.c_str());
        } else {
            LOG_WARNING("Language not specified in config file");
        }

        // Extract duration setting
        if (configJson.contains("duration")) {
            m_duration = configJson["duration"].get<int>();
            LOG_DEBUG("Parsed duration: %d", m_duration);
        } else {
            LOG_WARNING("Duration not specified in config file");
        }

        // Extract threshold setting
        if (configJson.contains("threshold")) {
            m_threshold = configJson["threshold"].get<float>();
            LOG_DEBUG("Parsed threshold: %.2f", m_threshold);
        } else {
            LOG_WARNING("Threshold not specified in config file");
        }

        // Extract command definitions
        if (configJson.contains("commands") && configJson["commands"].is_array()) {
            m_commands.clear(); // Clear existing commands

            for (const auto& cmd : configJson["commands"]) {
                CommandDefinition command;

                // Parse command name
                if (cmd.contains("name")) {
                    command.name = cmd["name"].get<std::string>();
                } else {
                    LOG_WARNING("Command without name found");
                    continue;
                }

                // Parse command trigger words
                if (cmd.contains("trigger_words") && cmd["trigger_words"].is_array()) {
                    for (const auto& word : cmd["trigger_words"]) {
                        command.triggerWords.push_back(word.get<std::string>());
                    }
                }

                // Parse command parameters
                if (cmd.contains("parameters") && cmd["parameters"].is_object()) {
                    for (const auto& param : cmd["parameters"].items()) {
                        command.parameters[param.key()] = param.value().get<std::string>();
                    }
                }

                // Parse command action
                if (cmd.contains("action")) {
                    command.action = cmd["action"].get<std::string>();
                }

                // Log the parsed command for debugging
                LOG_DEBUG("Parsed command: %s", command.name.c_str());
                LOG_DEBUG("  Trigger words: %zu items", command.triggerWords.size());
                LOG_DEBUG("  Action: %s", command.action.c_str());
                LOG_DEBUG("  Parameters: %zu items", command.parameters.size());

                m_commands.push_back(command);
            }
        } else {
            LOG_WARNING("No commands found or invalid commands format in config file");
        }

        // Extract additional model parameters if present
        if (configJson.contains("model_params") && configJson["model_params"].is_object()) {
            for (const auto& param : configJson["model_params"].items()) {
                m_modelParams[param.key()] = param.value().get<std::string>();
            }
        }

        LOG_INFO("Successfully parsed wakenet model configuration from %s", configFilePath.c_str());
        return true;

    } catch (const nlohmann::json::parse_error& e) {
        LOG_ERROR("JSON parsing error in config file %s: %s", configFilePath.c_str(), e.what());
        return false;
    } catch (const std::exception& e) {
        LOG_ERROR("Error parsing configuration file %s: %s", configFilePath.c_str(), e.what());
        return false;
    }
}

