    // Assuming 16kHz sampling rate (16000 samples per second)
    const size_t MAX_SAMPLES_2_SECONDS = 16000 * 2; // 32000 samples

    // Add new audio chunk to the buffer
    m_audioBuffer.insert(m_audioBuffer.end(), audioChunk.begin(), audioChunk.end());

