int EncodeWakeWordData()
{
    // Allocate memory for the task stack
    uint8_t* task_stack = (uint8_t*)malloc(TASK_STACK_SIZE);
    if (task_stack == NULL) {
        return -1; // Memory allocation failed
    }

    // Allocate memory for the encoded buffer
    uint8_t* encoded_buffer = (uint8_t*)malloc(ENCODED_BUFFER_SIZE);
    if (encoded_buffer == NULL) {
        free(task_stack);
        return -2; // Memory allocation failed
    }

    // Create a new task for background encoding
    TaskHandle_t encode_task = xTaskCreateStatic(
        EncodeWakeWordDataTask,
        "WakeWordEncoder",
        TASK_STACK_SIZE,
        NULL,
        TASK_PRIORITY,
        task_stack,
        NULL
    );

    if (encode_task == NULL) {
        free(task_stack);
        free(encoded_buffer);
        return -3; // Task creation failed
    }

    // Initialize Opus encoder with low complexity settings
    OpusEncoder* encoder = opus_encoder_create(SAMPLE_RATE, CHANNELS, OPUS_APPLICATION_VOIP, NULL);
    if (encoder == NULL) {
        free(task_stack);
        free(encoded_buffer);
        return -4; // Encoder creation failed
    }

    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0)); // Low complexity
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(BITRATE));

    // Process each PCM segment
    int total_encoded_bytes = 0;
    int segment_count = get_pcm_segment_count();

    for (int i = 0; i < segment_count; i++) {
        // Get PCM segment data
        uint8_t* pcm_data = get_pcm_segment(i);
        int pcm_length = get_pcm_segment_length(i);

        // Encode PCM data to Opus
        int encoded_bytes = opus_encode(encoder, 
                                       (opus_int16*)pcm_data, 
                                       pcm_length / sizeof(opus_int16), 
                                       encoded_buffer + total_encoded_bytes, 
                                       ENCODED_BUFFER_SIZE - total_encoded_bytes);

        if (encoded_bytes < 0) {
            // Handle encoding error
            opus_encoder_destroy(encoder);
            free(task_stack);
            free(encoded_buffer);
            return -5; // Encoding error
        }

        total_encoded_bytes += encoded_bytes;
    }

    // Append termination marker
    uint32_t termination_marker = TERMINATION_MARKER;
    memcpy(encoded_buffer + total_encoded_bytes, &termination_marker, sizeof(uint32_t));
    total_encoded_bytes += sizeof(uint32_t);

    // Signal availability of encoded data
    signal_encoded_data_ready(encoded_buffer, total_encoded_bytes);

    // Clean up resources
    opus_encoder_destroy(encoder);
    free(task_stack);
    free(encoded_buffer);

    return 0; // Success
}

bool GetWakeWordOpus(std::vector<uint8_t>& output_data) {
    // Lock the mutex to ensure thread-safe access to the queue
    std::unique_lock<std::mutex> lock(queue_mutex_);

    // Wait until there is data available in the queue
    // This will block the calling thread until data is available
    while (wake_word_queue_.empty()) {
        data_available_cv_.wait(lock);
    }

    // Retrieve the next available Opus-encoded wake word audio data
    // Since we're using swap to minimize copies, we'll move the data out of the queue
    output_data.swap(wake_word_queue_.front());

    // Remove the processed item from the queue
    wake_word_queue_.pop();

    // Return true if the retrieved data is non-empty, false otherwise
    return !output_data.empty();
}

#include <stdint.h>
#include "driver/i2c.h"

// Function to initialize XL9555 I/O expander
esp_err_t XL9555(i2c_master_bus_handle_t i2c_bus, uint8_t addr)
{
    esp_err_t ret;
    uint8_t config_data[2];

    // Configure port 0 (register 0x06) - Set all pins as output (0x00)
    // For XL9555, bit 0 = 0 means output, bit 1 = 1 means input
    // Setting all bits to 0x00 configures all pins as outputs
    config_data[0] = 0x00;  // Port 0 configuration register (0x06)

    // Configure port 1 (register 0x07) - Set all pins as output (0x00)
    config_data[1] = 0x00;  // Port 1 configuration register (0x07)

    // Write configuration to the device
    ret = i2c_master_write_to_device(i2c_bus, addr, config_data, 2, 1000 / portTICK_PERIOD_MS);
    if (ret != ESP_OK) {
        return ret;
    }

    // Optional: Initialize all output pins to low state
    uint8_t output_data[2];
    output_data[0] = 0x00;  // Port 0 output register (0x02)
    output_data[1] = 0x00;  // Port 1 output register (0x03)

    ret = i2c_master_write_to_device(i2c_bus, addr, output_data, 2, 1000 / portTICK_PERIOD_MS);
    if (ret != ESP_OK) {
        return ret;
    }

    return ESP_OK;
}

void SetOutputState(uint8_t pin, uint8_t level)
{
    // Define GPIO data register address (example address)
    volatile uint8_t* gpio_register = (volatile uint8_t*)0x40000000;

    // Read current register value
    uint8_t current_value = *gpio_register;

    // Calculate bit mask for the specific pin
    uint8_t bit_mask = 1 << pin;

    // Set or clear the specific bit based on level
    if (level != 0)
    {
        // Set the bit (output high)
        current_value |= bit_mask;
    }
    else
    {
        // Clear the bit (output low)
        current_value &= ~bit_mask;
    }

    // Write updated value back to register
    *gpio_register = current_value;
}

void InitializeI2c()
{
    // Initialize I2C bus with specified SDA and SCL pins
    // Enable internal pull-ups for both SDA and SCL lines

    // Configure I2C master interface
    // Set SDA pin (assuming GPIO pin 21 for SDA)
    // Set SCL pin (assuming GPIO pin 22 for SCL)

    // Enable I2C peripheral clock
    RCC->APB1ENR |= RCC_APB1ENR_I2C1EN;

    // Configure GPIO pins for I2C (SDA and SCL)
    // Enable GPIO clock for port B (assuming PB10 = SDA, PB11 = SCL)
    RCC->AHB1ENR |= RCC_AHB1ENR_GPIOBEN;

    // Configure SDA pin (PB10) as alternate function
    GPIOB->MODER &= ~(3UL << (10 * 2));      // Clear mode bits
    GPIOB->MODER |= (2UL << (10 * 2));       // Set as alternate function
    GPIOB->OTYPER &= ~(1UL << 10);           // Push-pull output
    GPIOB->OSPEEDR |= (3UL << (10 * 2));     // High speed
    GPIOB->PUPDR &= ~(3UL << (10 * 2));      // No pull-up/pull-down
    GPIOB->AFR[1] &= ~(0xF << ((10-8) * 4)); // Clear alternate function bits
    GPIOB->AFR[1] |= (4 << ((10-8) * 4));    // Set AF4 for I2C1

    // Configure SCL pin (PB11) as alternate function
    GPIOB->MODER &= ~(3UL << (11 * 2));      // Clear mode bits
    GPIOB->MODER |= (2UL << (11 * 2));       // Set as alternate function
    GPIOB->OTYPER &= ~(1UL << 11);           // Push-pull output
    GPIOB->OSPEEDR |= (3UL << (11 * 2));     // High speed
    GPIOB->PUPDR &= ~(3UL << (11 * 2));      // No pull-up/pull-down
    GPIOB->AFR[1] &= ~(0xF << ((11-8) * 4)); // Clear alternate function bits
    GPIOB->AFR[1] |= (4 << ((11-8) * 4));    // Set AF4 for I2C1

    // Configure I2C1 parameters
    I2C1->CR1 &= ~I2C_CR1_PE;                // Disable I2C peripheral

    // Set I2C clock frequency (assuming 50kHz)
    I2C1->CR2 = 50;                          // Set frequency to 50kHz

    // Configure I2C timing register for standard mode (100kHz)
    I2C1->TIMINGR = 0x00303D5B;              // Standard mode timing values

    // Enable internal pull-ups (if available on this controller)
    // For STM32, we enable internal pull-ups through GPIO configuration
    // Already handled by PUPDR settings above

    // Enable I2C peripheral
    I2C1->CR1 |= I2C_CR1_PE;

    // Wait for I2C to be ready
    while (!(I2C1->ISR & I2C_ISR_READY));

    // Initialize XL9555 I/O expander at address 0x20
    // First, check if device is responding
    uint8_t xl9555_address = 0x20;

    // Send start condition
    I2C1->CR2 |= I2C_CR2_START;

    // Wait for start condition to be sent
    while (!(I2C1->ISR & I2C_ISR_SB));

    // Send slave address with write bit
    I2C1->TXDR = (xl9555_address << 1) | 0;

    // Wait for address to be transmitted
    while (!(I2C1->ISR & I2C_ISR_ADDR));

    // Clear ADDR flag by reading ISR
    volatile uint32_t temp = I2C1->ISR;
    temp = I2C1->RXDR;

    // Configure XL9555 registers for proper operation
    // Set all ports to output (example configuration)
    // Port A direction register (0x00) - set all bits to 0 (output)
    // Port B direction register (0x01) - set all bits to 0 (output)

    // Write to configuration register for Port A (0x00)
    I2C1->TXDR = 0x00;  // Register address
    while (!(I2C1->ISR & I2C_ISR_TXIS));

    // Write data to configure all pins as outputs
    I2C1->TXDR = 0x00;  // All outputs
    while (!(I2C1->ISR & I2C_ISR_TXIS));

    // Generate stop condition
    I2C1->CR2 |= I2C_CR2_STOP;

    // Wait for stop condition to complete
    while (I2C1->CR2 & I2C_CR2_STOP);
}

