extern void downsampleAudio(short* input, short* output, size_t inputSize, size_t outputSize);
extern bool detectWifiCredentialsSignal(short* audioData, size_t dataSize, char* decodedCredentials);
extern void processWifiCredentials(const char* credentials);

int ReceiveWifiCredentialsFromAudio(Application* app, WifiManager* wifiMgr, Display* display, size_t bufferSize) {
    // Check if device is in WiFi configuration mode
    if (!app->isInWifiConfigMode) {
        display->showStatus("Not in WiFi config mode");
        return -1;
    }

    // Allocate buffers for audio processing
    short* audioBuffer = new short[bufferSize];
    short* monoBuffer = new short[bufferSize];
    short* downsampledBuffer = new short[bufferSize / 4]; // Downsample by factor of 4

    // Initialize buffers
    memset(audioBuffer, 0, bufferSize * sizeof(short));
    memset(monoBuffer, 0, bufferSize * sizeof(short));
    memset(downsampledBuffer, 0, (bufferSize / 4) * sizeof(short));

    int result = 0;

    try {
        // Read audio data from input source
        size_t samplesRead = readAudioData(audioBuffer, bufferSize);

        if (samplesRead == 0) {
            display->showStatus("No audio data received");
            result = -2;
            goto cleanup;
        }

        // Convert stereo to mono if necessary
        // Assuming we have stereo data with interleaved channels
        convertStereoToMono(audioBuffer, monoBuffer, samplesRead);

        // Downsample audio to reduce processing load
        downsampleAudio(monoBuffer, downsampledBuffer, samplesRead, bufferSize / 4);

        // Analyze audio to detect and decode WiFi credentials
        char credentials[256] = {0};
        if (detectWifiCredentialsSignal(downsampledBuffer, bufferSize / 4, credentials)) {
            // Successfully extracted credentials
            display->showStatus("WiFi credentials detected");

            // Process the extracted credentials
            processWifiCredentials(credentials);

            // Pass credentials to WiFi manager for connection setup
            // Assuming credentials are formatted as "SSID:PASSWORD"
            char* colonPos = strchr(credentials, ':');
            if (colonPos != nullptr) {
                *colonPos = '\0';
                char* password = colonPos + 1;
                wifiMgr->connectToWifi(credentials, password);
                display->showStatus("Connecting to WiFi...");
            } else {
                display->showStatus("Invalid credential format");
                result = -3;
                goto cleanup;
            }

            result = 0; // Success
        } else {
            display->showStatus("No WiFi credentials found in audio");
            result = -4;
        }

    } catch (...) {
        display->showStatus("Error processing audio data");
        result = -5;
    }

cleanup:
    // Clean up allocated memory
    delete[] audioBuffer;
    delete[] monoBuffer;
    delete[] downsampledBuffer;

    return result;
}

