#include <vector>
#include <cmath>
#include <algorithm>

// Constants for Goertzel algorithm
const float PI = 3.14159265358979323846f;
const int BUFFER_SIZE = 1024;  // Size of audio sample buffer
const int WINDOW_SIZE = 256;   // Size of processing window
const float SAMPLE_RATE = 8000.0f;  // Sample rate in Hz

// Goertzel algorithm parameters for mark and space tones
// Typical dial tone frequencies: Mark = 480Hz, Space = 620Hz
const float MARK_FREQ = 480.0f;
const float SPACE_FREQ = 620.0f;

std::vector<float> ProcessAudioSamples(const std::vector<float>& audio_samples) {
    static std::vector<float> buffer;
    static int buffer_index = 0;
    static bool is_initialized = false;

    // Initialize buffer if not already done
    if (!is_initialized) {
        buffer.resize(BUFFER_SIZE, 0.0f);
        is_initialized = true;
    }

    // Add new samples to buffer
    for (size_t i = 0; i < audio_samples.size(); ++i) {
        buffer[buffer_index % BUFFER_SIZE] = audio_samples[i];
        buffer_index++;
    }

    // Calculate number of complete windows we can process
    int num_windows = (buffer_index >= WINDOW_SIZE) ? 
                      (buffer_index - WINDOW_SIZE) / WINDOW_SIZE + 1 : 0;

    std::vector<float> probabilities;
    probabilities.reserve(num_windows);

    // Process each window
    for (int w = 0; w < num_windows; ++w) {
        // Extract window data
        std::vector<float> window_data(WINDOW_SIZE);
        for (int i = 0; i < WINDOW_SIZE; ++i) {
            window_data[i] = buffer[(buffer_index - WINDOW_SIZE - w * WINDOW_SIZE + i) % BUFFER_SIZE];
        }

        // Apply Goertzel algorithm for mark frequency detection
        float mark_magnitude = 0.0f;
        float space_magnitude = 0.0f;

        // Goertzel algorithm implementation for mark frequency
        float coeff_mark = 2.0f * cosf(2.0f * PI * MARK_FREQ / SAMPLE_RATE);
        float s_prev_mark = 0.0f;
        float s_prev2_mark = 0.0f;

        for (int i = 0; i < WINDOW_SIZE; ++i) {
            float s = window_data[i] + coeff_mark * s_prev_mark - s_prev2_mark;
            s_prev2_mark = s_prev_mark;
            s_prev_mark = s;
        }

        mark_magnitude = sqrtf(s_prev_mark * s_prev_mark + s_prev2_mark * s_prev2_mark - 
                              coeff_mark * s_prev_mark * s_prev2_mark);

        // Goertzel algorithm implementation for space frequency
        float coeff_space = 2.0f * cosf(2.0f * PI * SPACE_FREQ / SAMPLE_RATE);
        float s_prev_space = 0.0f;
        float s_prev2_space = 0.0f;

        for (int i = 0; i < WINDOW_SIZE; ++i) {
            float s = window_data[i] + coeff_space * s_prev_space - s_prev2_space;
            s_prev2_space = s_prev_space;
            s_prev_space = s;
        }

        space_magnitude = sqrtf(s_prev_space * s_prev_space + s_prev2_space * s_prev2_space - 
                               coeff_space * s_prev_space * s_prev2_space);

        // Calculate probability of mark tone presence (normalized)
        // Normalize by window size and peak amplitude
        float max_amplitude = 0.0f;
        for (int i = 0; i < WINDOW_SIZE; ++i) {
            max_amplitude = std::max(max_amplitude, std::abs(window_data[i]));
        }

        // Avoid division by zero
        if (max_amplitude > 0.0f) {
            float normalized_mark = mark_magnitude / (max_amplitude * WINDOW_SIZE);
            float normalized_space = space_magnitude / (max_amplitude * WINDOW_SIZE);

            // Simple probability calculation (normalized between 0 and 1)
            float probability = normalized_mark / (normalized_mark + normalized_space + 1e-8f);
            probabilities.push_back(probability);
        } else {
            probabilities.push_back(0.0f);
        }
    }

    return probabilities;
}

