{
    if (!isTransitioning_) {
        return;
    }

    unsigned long currentTime = millis();
    unsigned long elapsed = currentTime - transitionStartTime_;

    if (elapsed >= transitionDuration_) {
        // Transition complete
        currentBrightness_ = targetBrightness_;
        isTransitioning_ = false;
        StopBrightnessTimer(); // Assume this exists
        return;
    }

    // Calculate intermediate brightness value
    float progress = (float)elapsed / (float)transitionDuration_;
    // Apply easing function for smoother transition (optional)
    progress = EaseInOut(progress);

    // Calculate new brightness value
    int32_t diff = targetBrightness_ - currentBrightness_;
    uint8_t newBrightness = currentBrightness_ + (uint8_t)(diff * progress);

    // Update actual hardware
    UpdateHardwareBrightness(newBrightness);
    currentBrightness_ = newBrightness;
}

