Board::Board()
{
    // Initialize the board by ensuring we have a unique identifier
    // First, try to load existing UUID from persistent storage
    bool uuidLoaded = false;

    // Check if UUID exists in non-volatile memory
    uint8_t storedUUID[16];  // Assuming UUID is 16 bytes
    size_t bytesRead = 0;

    // Try to read UUID from persistent storage (e.g., flash memory, EEPROM)
    if (persistentStorageRead(UUID_STORAGE_ADDRESS, storedUUID, 16, &bytesRead) && 
        bytesRead == 16) {

        // Verify the UUID is valid (not all zeros or invalid pattern)
        bool isValidUUID = true;
        for (int i = 0; i < 16; i++) {
            if (storedUUID[i] != 0) {
                isValidUUID = false;
                break;
            }
        }

        if (!isValidUUID) {
            // Valid UUID found, use it
            memcpy(uuid_, storedUUID, 16);
            uuidLoaded = true;
        }
    }

    // If no valid UUID was loaded, generate a new one
    if (!uuidLoaded) {
        // Generate a new unique UUID
        generateUUID(uuid_);

        // Save the new UUID to persistent storage for future use
        persistentStorageWrite(UUID_STORAGE_ADDRESS, uuid_, 16);
    }
}

std::string Board::GenerateUuid() {
    // Generate 16 random bytes using ESP32's hardware random number generator
    uint8_t uuidBytes[16];
    for (int i = 0; i < 16; i++) {
        uuidBytes[i] = esp_random() & 0xFF;
    }

    // Set version bits (4 bits) - UUID version 4
    uuidBytes[6] = (uuidBytes[6] & 0x0F) | 0x40;

    // Set variant bits (2 bits) - RFC 4122 variant
    uuidBytes[8] = (uuidBytes[8] & 0x3F) | 0x80;

    // Format as UUID string: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    char uuidString[37]; // 36 characters + null terminator
    snprintf(uuidString, sizeof(uuidString),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuidBytes[0], uuidBytes[1], uuidBytes[2], uuidBytes[3],
             uuidBytes[4], uuidBytes[5], uuidBytes[6], uuidBytes[7],
             uuidBytes[8], uuidBytes[9], uuidBytes[10], uuidBytes[11],
             uuidBytes[12], uuidBytes[13], uuidBytes[14], uuidBytes[15]);

    return std::string(uuidString);
}

