std::string Board::GetSystemInfoJson() {
    // Create JSON object to hold system information
    JsonDocument doc;

    // Hardware details
    JsonObject hardware = doc["hardware"].to<JsonObject>();

    // Chip model
    #if defined(ESP32)
        hardware["chip_model"] = "ESP32";
    #elif defined(ESP8266)
        hardware["chip_model"] = "ESP8266";
    #else
        hardware["chip_model"] = "Unknown";
    #endif

    // Flash size
    hardware["flash_size_bytes"] = ESP.getFlashChipSize();

    // MAC address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    hardware["mac_address"] = std::string(mac_str);

    // Application metadata
    JsonObject application = doc["application"].to<JsonObject>();
    application["name"] = APP_NAME;
    application["version"] = APP_VERSION;
    application["compile_time"] = __DATE__ " " __TIME__;

    // Partition table data
    JsonObject partitions = doc["partitions"].to<JsonObject>();
    esp_partition_iterator_t iter = esp_partition_find(ESP_PARTITION_TYPE_APP, ESP_PARTITION_SUBTYPE_APP_FACTORY, NULL);
    if (iter != NULL) {
        const esp_partition_t* part = esp_partition_get(iter);
        partitions["factory_partition_size"] = part->size;
        partitions["factory_partition_address"] = part->address;
    }

    // Runtime information
    JsonObject runtime = doc["runtime"].to<JsonObject>();

    // Minimum free heap size
    runtime["min_free_heap_bytes"] = ESP.getMinFreeHeap();

    // Unique identifiers - UUID generation
    char uuid_str[37];
    uint32_t chipid = ESP.getChipId();
    snprintf(uuid_str, sizeof(uuid_str), "%08X-%04X-%04X-%04X-%08X",
             chipid, 
             (uint16_t)(chipid >> 16),
             (uint16_t)(chipid >> 32),
             (uint16_t)(chipid >> 48),
             (uint32_t)(chipid >> 64));
    runtime["uuid"] = std::string(uuid_str);

    // Additional runtime metrics
    runtime["uptime_seconds"] = millis() / 1000;
    runtime["free_heap_bytes"] = ESP.getFreeHeap();
    runtime["heap_fragmentation_percent"] = (float)(ESP.getMaxFreeBlockSize()) / (float)(ESP.getFreeHeap()) * 100.0f;

    // Serialize JSON to string
    std::string json_string;
    serializeJson(doc, json_string);

    return json_string;
}

