    // Configure I2C device with standard settings
    i2c_device_config_t dev_config = {
        .dev_addr_len = I2C_ADDR_BIT_LEN_7,
        .device_address = address,
        .scl_speed_hz = 100000,  // Standard I2C speed
        .scl_wait_time_ns = 0,
        .sda_hold_time_ns = 0,
        .sda_sample_time_ns = 0,
        .scl_start_setup_time_ns = 0,
        .scl_stop_setup_time_ns = 0,
        .scl_start_hold_time_ns = 0,
        .scl_stop_hold_time_ns = 0,
        .scl_rise_time_ns = 0,
        .scl_fall_time_ns = 0,
    };

    // Register the device with the I2C master bus
    esp_err_t result = i2c_master_bus_add_device(bus_handle, &dev_config, &this->device_handle);

    // Assert that device handle is valid after initialization
    assert(result == ESP_OK);
    assert(this->device_handle != NULL);
}

int WriteReg(uint8_t regAddr, uint8_t value)
{
    // Create buffer to hold register address and value
    uint8_t buffer[2];
    buffer[0] = regAddr;    // Register address
    buffer[1] = value;      // Value to write

    // Transmit the buffer via I2C master interface with 100ms timeout
    // Assuming I2C_Master_Transmit returns 0 for success, non-zero for error
    int result = I2C_Master_Transmit(buffer, 2, 100);

    // Return result (0 for success, non-zero for failure)
    return result;
}

uint8_t ReadReg(uint8_t regAddr)
{
    uint8_t data;

    // Write register address
    I2C_Write(deviceAddress, &regAddr, 1);

    // Read data from register
    I2C_Read(deviceAddress, &data, 1);

    return data;
}

