    }

    // Check if device is disconnected
    if (!IsConnected()) {
        return ICON_DISCONNECTED;
    }

    // Device is connected, check signal strength
    int signalStrength = GetSignalStrength();

    // Determine signal quality based on strength
    if (signalStrength >= SIGNAL_STRENGTH_STRONG) {
        return ICON_SIGNAL_STRONG;
    } else if (signalStrength >= SIGNAL_STRENGTH_FAIR) {
        return ICON_SIGNAL_FAIR;
    } else {
        return ICON_SIGNAL_WEAK;
    }
}

