bool SetPowerSaveLevel(PowerSaveLevel level)
{
    // Validate input parameter
    if (level < LOW_POWER || level > PERFORMANCE)
    {
        return false; // Invalid power save level
    }

    // Map general power save levels to Wi-Fi specific levels
    WifiPowerSaveLevel wifiLevel;

    switch (level)
    {
        case LOW_POWER:
            wifiLevel = WIFI_PS_LOW_POWER;
            break;
        case BALANCED:
            wifiLevel = WIFI_PS_BALANCED;
            break;
        case PERFORMANCE:
            wifiLevel = WIFI_PS_PERFORMANCE;
            break;
        default:
            return false; // Should not reach here due to validation above
    }

    // Apply the power save level through Wi-Fi manager instance
    // Assuming there's a global or member Wi-Fi manager instance
    WifiManager* wifiManager = GetWifiManagerInstance();

    if (wifiManager == nullptr)
    {
        return false; // Failed to get Wi-Fi manager instance
    }

    // Apply the setting
    bool result = wifiManager->SetPowerSaveLevel(wifiLevel);

    return result;
}

