esp_err_t SingleLed(gpio_num_t gpio_pin)
{
    // Initialize RMT peripheral for WS2812 communication
    rmt_config_t rmt_config = {
        .rmt_mode = RMT_MODE_TX,
        .channel = RMT_CHANNEL_0,
        .gpio_num = gpio_pin,
        .clk_div = 80,  // 80MHz / 80 = 1MHz clock (1us per tick)
        .mem_block_num = 1,
        .tx_config = {
            .carrier_en = false,
            .idle_level = RMT_IDLE_LEVEL_LOW,
            .idle_output_en = true,
        }
    };

    // Configure RMT channel
    esp_err_t ret = rmt_config(&rmt_config);
    if (ret != ESP_OK) {
        return ret;
    }

    // Install RMT driver
    ret = rmt_driver_install(rmt_config.channel, 0, 0);
    if (ret != ESP_OK) {
        return ret;
    }

    // Initialize LED state - turn off initially
    // Create RMT data for OFF state (0x00000000 for RGB=0,0,0)
    rmt_data_t led_off_data[24];
    for (int i = 0; i < 24; i++) {
        led_off_data[i] = (rmt_data_t){.level0 = 0, .duration0 = 1, .level1 = 0, .duration1 = 1};
    }

    // Send OFF command to clear LED
    ret = rmt_write_items(rmt_config.channel, led_off_data, 24, true);
    if (ret != ESP_OK) {
        return ret;
    }

    // Setup timer for blinking functionality
    // Using timer group 0, timer 0
    timer_config_t timer_config = {
        .divider = 80,  // 1MHz timer clock
        .counter_dir = TIMER_COUNT_UP,
        .counter_en = TIMER_PAUSE,
        .alarm_en = TIMER_ALARM_EN,
        .auto_reload = true,
    };

    ret = timer_init(TIMER_GROUP_0, TIMER_0, &timer_config);
    if (ret != ESP_OK) {
        return ret;
    }

    // Set alarm value for 1 second period (1000000 ticks at 1MHz)
    ret = timer_set_alarm_value(TIMER_GROUP_0, TIMER_0, 1000000);
    if (ret != ESP_OK) {
        return ret;
    }

    // Enable timer interrupt
    ret = timer_enable_intr(TIMER_GROUP_0, TIMER_0);
    if (ret != ESP_OK) {
        return ret;
    }

    // Register timer callback for blinking control
    ret = timer_isr_register(TIMER_GROUP_0, TIMER_0, NULL, 0, NULL);
    if (ret != ESP_OK) {
        return ret;
    }

    return ESP_OK;
}

