bool SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Validate input
    if (!packet) {
        return false;
    }

    // Thread-safe access to UDP channel using mutex
    static std::mutex udp_mutex;
    std::lock_guard<std::mutex> lock(udp_mutex);

    try {
        // Prepare encryption parameters
        // Create nonce from packet size, timestamp, and sequence number
        uint32_t packet_size = packet->payload.size();
        uint64_t timestamp = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::high_resolution_clock::now().time_since_epoch()).count();
        uint32_t sequence_number = packet->sequence_number;

        // Construct nonce (12 bytes for AES-CTR)
        std::array<uint8_t, 12> nonce;
        std::memcpy(nonce.data(), &packet_size, sizeof(packet_size));
        std::memcpy(nonce.data() + 4, &timestamp, sizeof(timestamp));
        std::memcpy(nonce.data() + 12 - sizeof(sequence_number), &sequence_number, sizeof(sequence_number));

        // Encrypt payload using AES-CTR mode
        // Assuming we have access to AES-CTR encryption function
        std::vector<uint8_t> encrypted_payload = aes_ctr_encrypt(
            packet->payload, 
            get_encryption_key(),  // Function to retrieve current encryption key
            nonce
        );

        // Create UDP packet with encrypted payload
        std::vector<uint8_t> udp_packet;
        // Add header information (size, timestamp, sequence number)
        udp_packet.resize(sizeof(uint32_t) * 3 + encrypted_payload.size());

        uint32_t* header = reinterpret_cast<uint32_t*>(udp_packet.data());
        header[0] = packet_size;                    // Original packet size
        header[1] = static_cast<uint32_t>(timestamp); // Timestamp
        header[2] = sequence_number;                // Sequence number

        // Copy encrypted payload
        std::memcpy(udp_packet.data() + sizeof(uint32_t) * 3, 
                   encrypted_payload.data(), 
                   encrypted_payload.size());

        // Transmit over UDP
        // Assuming we have a UDP socket object available
        static std::unique_ptr<UDPSocket> udp_socket = create_udp_socket();

        if (!udp_socket) {
            return false;
        }

        // Send the packet
        bool success = udp_socket->send_to(
            udp_packet,
            get_destination_address(),  // Function to get destination address
            get_destination_port()      // Function to get destination port
        );

        return success;

    } catch (const std::exception& e) {
        // Handle any encryption or network errors
        return false;
    } catch (...) {
        // Handle any other unexpected errors
        return false;
    }
}

