bool MqttProtocol::OpenAudioChannel() {
    // Step 1: Connect to MQTT server
    if (!ConnectToMqttServer()) {
        return false;
    }

    // Step 2: Send hello message
    if (!SendHelloMessage()) {
        DisconnectFromMqttServer();
        return false;
    }

    // Step 3: Wait for server response with timeout
    const int timeoutSeconds = 5;
    const auto startTime = std::chrono::steady_clock::now();

    bool serverResponseReceived = false;
    while (!serverResponseReceived) {
        auto currentTime = std::chrono::steady_clock::now();
        auto elapsedSeconds = std::chrono::duration_cast<std::chrono::seconds>(currentTime - startTime).count();

        if (elapsedSeconds > timeoutSeconds) {
            DisconnectFromMqttServer();
            return false;
        }

        // Check for server response
        if (CheckForServerResponse()) {
            serverResponseReceived = true;
            break;
        }

        // Small delay to prevent busy waiting
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }

    // Step 4: Validate server response
    if (!ValidateServerResponse()) {
        DisconnectFromMqttServer();
        return false;
    }

    // Step 5: Establish UDP connection for audio packets
    if (!EstablishUdpConnection()) {
        DisconnectFromMqttServer();
        return false;
    }

    // Step 6: Set up audio packet processing
    if (!SetupAudioProcessing()) {
        CleanupAudioChannel();
        return false;
    }

    // Step 7: Start listening for audio packets
    m_audioThread = std::thread(&MqttProtocol::ProcessAudioPackets, this);

    // Step 8: Mark channel as open
    m_isAudioChannelOpen = true;

    return true;
}

