int CharToHex(char c) {
    if (c >= '0' && c <= '9') {
        return c - '0';
    }
    else if (c >= 'A' && c <= 'F') {
        return c - 'A' + 10;
    }
    else if (c >= 'a' && c <= 'f') {
        return c - 'a' + 10;
    }
    else {
        return 0;
    }
}

std::string MqttProtocol::DecodeHexString(const std::string &hexString) {
    std::string result;

    // Process the hex string two characters at a time
    for (size_t i = 0; i < hexString.length(); i += 2) {
        // Check if we have at least two characters left
        if (i + 1 >= hexString.length()) {
            // Handle odd length - skip the last character or handle as needed
            // For this implementation, we'll ignore incomplete pairs
            break;
        }

        // Extract two characters
        char hexChar1 = hexString[i];
        char hexChar2 = hexString[i + 1];

        // Convert hex characters to decimal values
        int val1 = 0, val2 = 0;

        // Convert first hex character
        if (hexChar1 >= '0' && hexChar1 <= '9') {
            val1 = hexChar1 - '0';
        } else if (hexChar1 >= 'a' && hexChar1 <= 'f') {
            val1 = hexChar1 - 'a' + 10;
        } else if (hexChar1 >= 'A' && hexChar1 <= 'F') {
            val1 = hexChar1 - 'A' + 10;
        } else {
            // Invalid hex character, skip this pair
            continue;
        }

        // Convert second hex character
        if (hexChar2 >= '0' && hexChar2 <= '9') {
            val2 = hexChar2 - '0';
        } else if (hexChar2 >= 'a' && hexChar2 <= 'f') {
            val2 = hexChar2 - 'a' + 10;
        } else if (hexChar2 >= 'A' && hexChar2 <= 'F') {
            val2 = hexChar2 - 'A' + 10;
        } else {
            // Invalid hex character, skip this pair
            continue;
        }

        // Combine the two hex values into one byte
        unsigned char byteValue = static_cast<unsigned char>((val1 << 4) | val2);

        // Append to result
        result.push_back(byteValue);
    }

    return result;
}

